Write-Host ">> Patch permissions..." -ForegroundColor Cyan
$f3 = "src\services\permissions.ts"
$lines3 = [System.IO.File]::ReadAllLines("$PWD\$f3", [System.Text.Encoding]::UTF8)
$list3 = [System.Collections.Generic.List[string]]$lines3
for ($i = 0; $i -lt $list3.Count; $i++) {
  if ($list3[$i] -match "voir_email_parents: boolean;" -and $list3[$i+1] -notmatch "voir_portail_pub") {
    $list3.Insert($i+1, "  voir_portail_public: boolean;")
  }
  if ($list3[$i] -match "voir_email_parents: true," -and $list3[$i] -notmatch "voir_portail_pub") {
    $list3[$i] = $list3[$i].TrimEnd() + " voir_portail_public: true,"
  }
  if ($list3[$i] -match "voir_email_parents: false," -and $list3[$i] -notmatch "voir_portail_pub") {
    $list3[$i] = $list3[$i].TrimEnd() + " voir_portail_public: false,"
  }
  if ($list3[$i] -match "voir_email_parents.*modules.push" -and $list3[$i+1] -notmatch "portail-public") {
    $list3.Insert($i+1, "  if (p.voir_portail_public)    modules.push('portail-public');")
  }
}
[System.IO.File]::WriteAllLines("$PWD\$f3", $list3, [System.Text.Encoding]::UTF8)
Write-Host "   Permissions OK" -ForegroundColor Green

Write-Host "`n>> TypeScript check..." -ForegroundColor Cyan
npx tsc --noEmit
if ($LASTEXITCODE -ne 0) { Write-Host "ERREUR TypeScript" -ForegroundColor Red; exit 1 }
Write-Host "   OK" -ForegroundColor Green

git add -A
git commit -m "feat(B5.6): Portail Public - page publique ecole + gestion back-office"
npx vercel --prod
Write-Host "`n OK B5.6 deploye" -ForegroundColor Green
